fn divide(a: f64, b: f64) -> Result<f64, String> {
    if b == 0.0 {
        Err(String::from("division by zero"))
    } else {
        Ok(a / b)
    }
}

fn main() {
    println!("{:?}", divide(10.0, 2.0));
    println!("{:?}", divide(10.0, 0.0));
}

fn parse_number(s: &str) -> Result<i32, String> {
    s.parse::<i32>().map_err(|e| e.to_string())
}

fn main() {
    match parse_number("42") {
        Ok(n)  => println!("Parsed: {}", n),
        Err(e) => println!("Error: {}", e),
    }
    match parse_number("abc") {
        Ok(n)  => println!("Parsed: {}", n),
        Err(e) => println!("Error: {}", e),
    }
}

fn double_parsed(s: &str) -> Result<i32, String> {
    let n = s.parse::<i32>().map_err(|e| e.to_string())?;
    Ok(n * 2)
}

fn main() {
    println!("{:?}", double_parsed("21"));
    println!("{:?}", double_parsed("oops"));
}

fn main() {
    let n: i32 = "42".parse().expect("hardcoded literal always parses");
    println!("{}", n);

    let v = vec![1, 2, 3];
    println!("{}", v.get(1).unwrap());
}

fn main() {
    let doubled = "21".parse::<i32>()
        .map(|n| n * 2);
    println!("{:?}", doubled);

    let result = "10".parse::<i32>()
        .and_then(|n| if n > 0 { Ok(n) } else { Err("negative".parse::<i32>().unwrap_err()) });
    println!("{:?}", result);
}

fn main() {
    let good: Result<i32, &str> = Ok(42);
    let bad:  Result<i32, &str> = Err("oops");

    println!("{}", good.unwrap_or(0));
    println!("{}", bad.unwrap_or(0));
    println!("{}", bad.unwrap_or_else(|e| {
        println!("error was: {}", e);
        -1
    }));
}

fn main() {
    let strings = vec!["1", "2", "3", "four", "5"];
    let result: Result<Vec<i32>, _> = strings.iter()
        .map(|s| s.parse::<i32>())
        .collect();
    println!("{:?}", result);

    let ok_strings = vec!["1", "2", "3"];
    let ok: Result<Vec<i32>, _> = ok_strings.iter()
        .map(|s| s.parse::<i32>())
        .collect();
    println!("{:?}", ok);
}

fn get_item(v: &[i32], i: usize) -> i32 {
    if i >= v.len() {
        panic!("index {} out of bounds for len {}", i, v.len());
    }
    v[i]
}

fn main() {
    let v = vec![10, 20, 30];
    println!("{}", get_item(&v, 1));
}
